			'"use client";\n\nimport { cn } from "../../../registry/lib/utils";\nimport { Button } from "../../../registry/ui/button";\nimport { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from "../../../registry/ui/card";\nimport { Input } from "../../../registry/ui/input";\nimport { TextField } from "../../../registry/ui/text-field";\n\nexport function TeamName({ className, ...props }: React.ComponentProps<"div">) {\n\treturn (\n\t\t<Card className={cn("", className)} {...props}>\n\t\t\t<CardHeader>\n\t\t\t\t<CardTitle>Team Name</CardTitle>\n\t\t\t\t<CardDescription>Your team\'s visible name across the platform.</CardDescription>\n\t\t\t</CardHeader>\n\t\t\t<CardContent>\n\t\t\t\t<TextField aria-label="Team Name" defaultValue="My Team">\n\t\t\t\t\t<Input />\n\t\t\t\t</TextField>\n\t\t\t</CardContent>\n\t\t\t<CardFooter className="flex items-center justify-between gap-4">\n\t\t\t\t<p className="text-sm text-fg-muted">Please use 32 characters at maximum.</p>\n\t\t\t\t<Button variant="primary">Save</Button>\n\t\t\t</CardFooter>\n\t\t</Card>\n\t);\n}\n',
